// LoadCreatorUser loads the reviewTask's CreatorUser into the .R struct
func (o *ReviewTask) LoadCreatorUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CreatorUser = nil

	related, err := o.CreatorUser(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.CreatorReviewTasks = ReviewTaskSlice{o}

	o.R.CreatorUser = related
	return nil
}

// LoadCreatorUser loads the reviewTask's CreatorUser into the .R struct
func (os ReviewTaskSlice) LoadCreatorUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.CreatorUser(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range users {
			if !o.CreatorID.IsValue() {
				continue
			}

			if !(o.CreatorID.IsValue() && o.CreatorID.MustGet() == rel.ID) {
				continue
			}

			rel.R.CreatorReviewTasks = append(rel.R.CreatorReviewTasks, o)

			o.R.CreatorUser = rel
			break
		}
	}

	return nil
}

